import{_ as e,o as r,c as a,a4 as d}from"./chunks/framework.BybBnFXO.js";const u=JSON.parse('{"title":"Color Cause","description":"","frontmatter":{"title":"Color Cause"},"headers":[],"relativePath":"color-causes/intro.md","filePath":"color-causes/intro.md","lastUpdated":1784177547000}'),o={name:"color-causes/intro.md"};function i(n,t,s,l,c,h){return r(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="color-cause" tabindex="-1">Color Cause <a class="header-anchor" href="#color-cause" aria-label="Permalink to &quot;Color Cause&quot;">​</a></h1><p>Color in gems is never arbitrary. Three primary mechanisms account for nearly all natural colored stones:</p><h2 id="three-primary-mechanisms" tabindex="-1">Three Primary Mechanisms <a class="header-anchor" href="#three-primary-mechanisms" aria-label="Permalink to &quot;Three Primary Mechanisms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mechanism</th><th>Summary</th></tr></thead><tbody><tr><td><a href="./transition-metal.html">Transition-Metal Ion Coloration</a></td><td>Transition-metal ions (Cr, Fe, Mn, Co, Ni, V, Cu, Ti) have</td></tr><tr><td>partially filled d or f orbitals. When substituted into a host</td><td></td></tr><tr><td>lattice, crystal-field splitting creates d-d absorption bands</td><td></td></tr><tr><td>in the visible spectrum. The unabsorbed wavelengths produce</td><td></td></tr><tr><td>the gem&#39;s color. This is the dominant cause of color in</td><td></td></tr><tr><td>gemstones — roughly 70% of colored gems owe their hue to it.</td><td></td></tr><tr><td></td><td></td></tr><tr><td><a href="./color-centers.html">Color Centers</a></td><td>Color centers are point defects in a crystal lattice that</td></tr><tr><td>selectively absorb visible light. When an ion is missing</td><td></td></tr><tr><td>(vacancy), extra (interstitial), or substituted by an impurity,</td><td></td></tr><tr><td>nearby electrons or holes become trapped. Their energy levels</td><td></td></tr><tr><td>often fall in the visible range, producing color. Color centers</td><td></td></tr><tr><td>form naturally via radiation, or via artificial irradiation</td><td></td></tr><tr><td>(which may fade with sunlight exposure — a key tell for</td><td></td></tr><tr><td>treated material).</td><td></td></tr><tr><td></td><td></td></tr><tr><td><a href="./charge-transfer.html">Charge Transfer</a></td><td>Charge transfer involves an electron hopping between adjacent</td></tr><tr><td>ions or between different energy states of the same ion, driven</td><td></td></tr><tr><td>by absorbed photons. Compared to d-d transitions, charge-</td><td></td></tr><tr><td>transfer absorption is typically 10²–10⁴ times stronger, so</td><td></td></tr><tr><td>even trace concentrations of the relevant elements can produce</td><td></td></tr><tr><td>saturated, vivid colors. Subtypes include metal–metal (MMCT),</td><td></td></tr><tr><td>oxygen–metal (OMCT), and metal–ligand (MLCT).</td><td></td></tr><tr><td></td><td></td></tr></tbody></table><p><em>See the <a href="./../classification/intro.html">classification overview</a> for the mineralogical framework.</em></p>',5)])])}const f=e(o,[["render",i]]);export{u as __pageData,f as default};
